import { Component, EventEmitter, Input, Output } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { NgbActiveModal, NgbModal } from '@ng-bootstrap/ng-bootstrap';
import { TableColumn, TableConfig } from '../../../../../shared/components/table-advanced/table-advanced-interfaces';
import { PettyCashService } from '../../../cashier/petty-cash/services/petty-cash.service';
import { SharedService } from '../../../../../services/shared.service';
import { ExcelService } from '../../../../../services/excel.service';
import { Section } from '../../../../../shared/Interfaces/IExcel';
import { CommonService } from '../../../../../services/common.service';

@Component({
  selector: 'app-expense-request-details',
  templateUrl: './expense-request-details.component.html',
  styleUrls: ['./expense-request-details.component.scss']
})
export class ExpenseRequestDetailsComponent {
  @Input() data;
  approvedRequestList = [];
  details;
  confirmReceivingVoucherAttachment;
  //Data Table
  tableColumns: TableColumn[] = [];
  loading = false;
  pageNo = 1;
  total = 0;
  limit = 4;
  tableConfig: TableConfig = {
    filter: {
      Sort: 1,
      PageSize: this.limit,
    },
    hideTotalRecord: true,
    infiniteScroll: {
      isScroll: true,
    },
    style: {
      otherStyle: {
        height: '170px',
        overflow: 'auto'
      }
    }
  };

  constructor(
    private pettyCashService: PettyCashService,
    private sharedService: SharedService,
    public activeModal: NgbActiveModal,
    private _excelService: ExcelService,
    private _commonService: CommonService,

  ) { }

  ngOnInit(): void {
    this.initTableColumns();
    this.getPettyCashRequestExpensesList();
    this.getRegisterPettycashrequestDetails();
  }
  exportToExcel(expenseList) {
    let requestDetails = [
      this.details?.register?.branch?.branchName,
      this.details?.register?.registerId,
      this.details?.register?.registersName,
      this.details?.pettyCashRequestId,
      this._commonService.transformDecimal(this.details?.requestedAmount),
      this._commonService.transformDecimal(this.details?.approvedAmount),
      this.details?.requestNote,
    ]
    let expenseDetails = expenseList.map((item, index) => {
      return [
        index + 1,
        item?.invoiceNo,
        this._commonService.transformDate(item?.invoiceDate),
        item?.category[0]?.lookupName,
        item?.costCenter?.costCenterName,
        item?.costCenter?.approverUser?.fullName,
        item?.managerApproval?.approvername,
        this._commonService.transformDecimal(item?.expenseTotalAmount),
        this._commonService.transformDate(this.data?.providedAt),
      ]
    })
    const sections: Section[] = [
      {
        headers: ['Branch Name', 'Register No.', 'Regsiter Name', 'Request No.', 'Requested Amount', 'Provided Amount', 'Notes'],
        data: requestDetails,
        heading: ['Request Details'],
        showAsKeyValue: true,
      },
      {
        headers: ['Seq', 'Invoice No.', 'Invoice Date', 'Category', 'Cost Center Name', 'Cost Center Approver','Approved By', 'Amount', 'Providing Date'],
        data: expenseDetails,
        heading: ['Expense Details'],
      },
    ];
    this._excelService.exportToExcelJs({ sections, fileName: 'Petty_Cash_Replenishment_Report', mainHeading: 'Petty Cash Replenishment Report' });
  }
  exportApprovedPettyCashRequestExpensesList() {
    let params = `?RegisterId=${this.data.registerId}&ReplenishmentRequestID=${this.data.pettyCashRequestId}&pageNo=0&pageSize=10000`;
    this.pettyCashService.getPettyCashRequestExpensesList(params).subscribe({
      next: (response: any) => {
        let approvedExp = response?.data?.data.filter(x => x.status == 2004);
        this.exportToExcel(approvedExp);
      }
    })
  }
  getRegisterPettycashrequestDetails() {
    this.pettyCashService.GetRegisterPettycashrequestDetails(this.data.pettyCashRequestId).subscribe((response: any) => {
      this.details = response.data;
    })
  }
  onsScrollUpdate(event) {
    if (event?.scrolled) {
      this.pageNo += 1;
      this.getPettyCashRequestExpensesList();
    }
  }
  getPettyCashRequestExpensesList() {
    let params = `?RegisterId=${this.data.registerId}&ReplenishmentRequestID=${this.data.pettyCashRequestId}&pageNo=${this.pageNo - 1}&pageSize=${this.tableConfig.filter.PageSize}`
    this.pettyCashService.getPettyCashRequestExpensesList(params).subscribe((response: any) => {
      if (response?.isSuccess) {
        let data = response.data.data;
        if (!data?.length) {
          return;
        }
        let approvedExp = data.filter(x => x.status == 2004);
        this.approvedRequestList = [...this.approvedRequestList, ...approvedExp];
        this.total = response.data?.totalRecordCount;
        this.confirmReceivingVoucherAttachment = response?.data?.info?.confirnReceivingVoucher;
      }
    })
  }
  onPageChange(page: number) {
    this.pageNo = page;
    this.getPettyCashRequestExpensesList();
  }
  initTableColumns() {
    this.tableColumns = [
      { key: 'invoiceNo', label: 'Invoice No' },
      { key: 'invoiceDate', label: 'Invoice Date', },
      { key: 'category[0].lookupName', label: 'Category', },
      { key: 'costCenter.costCenterName', label: 'Cost Center Name', },
      { key: 'costCenter.approverUser.fullName', label: 'Cost Center Approver' },
      { key: 'managerApproval.approvername', label: 'Approved By', placeholder:'---' },
      { key: 'expenseTotalAmount', label: 'Amount', },
      { key: 'createdAt', label: 'Date', },
    ];
  }
}
